const cntS = (n) => { let c=0; for(const x of n){ if(x.type==="section")c++; if(x.children)c+=cntS(x.children); } return c; };
const rMd = t => t.replace(/^### (.+)$/gm,'<h3 style="font-size:15px;font-weight:700;color:#e4e4e7;margin:16px 0 6px">$1</h3>').replace(/^## (.+)$/gm,'<h2 style="font-size:17px;font-weight:700;color:#fbbf24;margin:20px 0 8px">$1</h2>').replace(/\*\*(.+?)\*\*/g,'<strong style="color:#e4e4e7">$1</strong>').replace(/^[•\-] (.+)$/gm,'<div style="padding-left:16px;position:relative;margin:3px 0"><span style="position:absolute;left:0;color:#d4a953">◆</span> $1</div>').replace(/\n/g,'<br/>');

/** แปลง tag สตริง: ข้อความธรรมดา | URL เต็ม | รูปแบบ ชื่อที่แสดง|https://... */
function parseVideoTag(raw) {
  const s = String(raw).trim();
  if (!s) return { type: "text", label: s, href: null };
  const pipe = s.indexOf("|");
  if (pipe > 0) {
    const label = s.slice(0, pipe).trim();
    const url = s.slice(pipe + 1).trim();
    if (/^https?:\/\//i.test(url))
      return { type: "link", label: label || shortLinkLabel(url), href: url };
  }
  if (/^https?:\/\//i.test(s)) return { type: "link", label: shortLinkLabel(s), href: s };
  return { type: "text", label: s, href: null };
}
function shortLinkLabel(url) {
  try {
    const u = new URL(url);
    const p = u.pathname.toLowerCase();
    if (u.hostname.includes("docs.google.com")) return "Google Doc";
    if (u.hostname.includes("drive.google.com")) return "Google Drive";
    if (/\.pdf(\?|$)/i.test(p) || p.endsWith(".pdf")) return "PDF";
    return u.hostname.replace(/^www\./i, "");
  } catch {
    return "ลิงก์";
  }
}
function tagDisplayLabel(raw) {
  return parseVideoTag(raw).label;
}
function tagMatchesQuery(raw, ql) {
  if (!ql) return true;
  const p = parseVideoTag(raw);
  if (p.label.toLowerCase().includes(ql)) return true;
  if (p.href && p.href.toLowerCase().includes(ql)) return true;
  return String(raw).toLowerCase().includes(ql);
}
function VideoTagChip({ raw }) {
  const p = parseVideoTag(raw);
  const base = "text-[11px] px-2 py-0.5 rounded-md border max-w-full min-w-0";
  if (p.type === "link" && p.href)
    return (
      <a
        href={p.href}
        target="_blank"
        rel="noopener noreferrer"
        onClick={(e) => e.stopPropagation()}
        className={`${base} inline-flex items-center gap-1 bg-sky-500/15 text-sky-300 border-sky-500/30 hover:bg-sky-500/25 hover:border-sky-400/40 truncate`}
      >
        <ExternalLink size={10} className="flex-shrink-0 opacity-90" aria-hidden />
        <span className="truncate">{p.label}</span>
      </a>
    );
  return <span className={`${base} inline-block bg-zinc-800 text-zinc-400 border-zinc-700/50 truncate`}>{p.label}</span>;
}

